const fs = require('fs');
const path = require('path');
const customHtmlReporter = require('./custom-html-reporter.cjs');

module.exports = async () => {
  // Path to the final coverage data generated by Jest
  const coverageFilePath = path.resolve(__dirname, 'coverage', 'coverage-final.json');
  
  if (fs.existsSync(coverageFilePath)) {
    const coverageMap = JSON.parse(fs.readFileSync(coverageFilePath, 'utf8'));
    
    // Invoke the custom HTML reporter
    customHtmlReporter(coverageMap);
  } else {
    console.error("Coverage file not found: ", coverageFilePath);
  }
};
